import React, { useEffect, useState, useRef } from "react";
import { linkHomeDesign as design } from "../../../design/linkHomeDesign";
import LinkShow from "./LinkShow";
import LinkAdd from "./LinkAdd";
import { showAddSuccessToast } from "../../../utils/toast/successAddToast";


const API = "http://localhost:5000/api/links";

const sortOptions = [
  { label: "Sort by Position", value: "order" },
  { label: "Sort by Name", value: "name" },
  { label: "Sort by Status", value: "status" },
];

const statusOptions = [
  { label: "Active", value: true },
  { label: "Inactive", value: false },
];

const LinkHome = () => {
  const [links, setLinks] = useState([]);
  const [view, setView] = useState("home");
  const [sort, setSort] = useState("order");
  const [search, setSearch] = useState("");
  const [dropdownOpen, setDropdownOpen] = useState(false);
  const [statusDropdown, setStatusDropdown] = useState(false);
  const [nameError, setNameError] = useState("");
  const [editId, setEditId] = useState(null);

  const dropdownRef = useRef(null);
  const statusRef = useRef(null);

  const [name, setName] = useState("");
  const [isActive, setIsActive] = useState(true);

  const fetchLinks = async () => {
    const res = await fetch(API);
    const data = await res.json();
    setLinks(data.filter((l) => !l.parent));
  };

  useEffect(() => {
    fetchLinks();
  }, []);

  useEffect(() => {
    const handler = (e) => {
      if (!dropdownRef.current?.contains(e.target))
        setDropdownOpen(false);
      if (!statusRef.current?.contains(e.target))
        setStatusDropdown(false);
    };

    document.addEventListener("mousedown", handler);
    return () =>
      document.removeEventListener("mousedown", handler);
  }, []);

  const processedLinks = [...links]
    .filter((l) =>
      l.name.toLowerCase().includes(search.toLowerCase())
    )
    .sort((a, b) => {
      if (sort === "name") return a.name.localeCompare(b.name);
      if (sort === "status") return b.isActive - a.isActive;
      return 0;
    });


const handleSubmit = async (e) => {
  e.preventDefault();

  setNameError("");

  // duplicate check (ignore current editing item)
  const exist = links.find(
    (l) =>
      l.name.toLowerCase() === name.toLowerCase() &&
      l._id !== editId
  );

  if (exist) {
    setNameError("Link name already exists");
    return;
  }

  let res;

  if (editId) {
    // UPDATE
    res = await fetch(`${API}/${editId}`, {
      method: "PUT",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ name, isActive }),
    });
  } else {
    // CREATE
    res = await fetch(API, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ name, isActive, parent: null }),
    });
  }

  if (res.ok) {
    setName("");
    setIsActive(true);
    setEditId(null);
    setView("home");
    fetchLinks();
  }
};


const handleDelete = async (id) => {
  const confirmDelete = window.confirm("Are you sure?");
  if (!confirmDelete) return;

  const res = await fetch(`${API}/${id}`, {
    method: "DELETE",
  });

  if (res.ok) {
    fetchLinks();
  }
};



const handleEdit = (link) => {
  setName(link.name);
  setIsActive(link.isActive);
  setEditId(link._id);   // store id
  setView("add");        // open form
};


  return (
    <div className={design.pageWrapper}>
      <div className={design.container}>

        {/* ===== HEADER FIXED HERE ===== */}
        <div className={design.header}>
          <h1 className={design.title}>
            Parent Navigation Links
          </h1>

          <p className={design.subtitle}>
            Manage only main menu navigation.
          </p>

          <div className={design.pathWrapper}>
            {view === "home" && (
              <span className={design.pathActive}>
                linkhome
              </span>
            )}

            {view === "add" && (
              <>
                <span
                  onClick={() => setView("home")}
                  className={design.path}
                >
                  linkhome
                </span>
                <span className={design.pathDivider}>
                  /
                </span>
                <span className={design.pathActive}>
                        {editId ? "update-link" : "add-link"}

                </span>
              </>
            )}
          </div>
        </div>
        {/* ===== END HEADER ===== */}

        {view === "home" && (
          <LinkShow
            links={processedLinks}
            search={search}
            setSearch={setSearch}
            sort={sort}
            setSort={setSort}
            sortOptions={sortOptions}
            dropdownOpen={dropdownOpen}
            setDropdownOpen={setDropdownOpen}
            dropdownRef={dropdownRef}
            setView={setView}

              handleDelete={handleDelete}
  handleEdit={handleEdit}
          />
        )}

        {view === "add" && (
<LinkAdd
  name={name}
  setName={setName}
  isActive={isActive}
  setIsActive={setIsActive}
  statusOptions={statusOptions}
  statusDropdown={statusDropdown}
  setStatusDropdown={setStatusDropdown}
  statusRef={statusRef}
  handleSubmit={handleSubmit}
  setView={setView}
  nameError={nameError}
  editId={editId}
/>
        )}
      </div>
    </div>
  );
};

export default LinkHome;
